/*!50001 CREATE ALGORITHM=UNDEFINED */
/*!50013 DEFINER=`root`@`localhost` SQL SECURITY DEFINER */
/*!50001 VIEW `v_asistencia_por_materia` AS select `i`.`alumno_id` AS `alumno_id`,`u`.`nombre` AS `nombre`,`u`.`apellido` AS `apellido`,`u`.`legajo` AS `legajo`,`u`.`curso` AS `curso`,`m`.`id` AS `materia_id`,`m`.`nombre` AS `materia`,count(`c`.`id`) AS `total_clases`,sum(`a`.`estado` in ('presente','tardanza')) AS `clases_presentes`,round(sum(`a`.`estado` in ('presente','tardanza')) / nullif(count(`c`.`id`),0) * 100,1) AS `porcentaje` from ((((`inscripciones` `i` join `usuarios` `u` on(`u`.`id` = `i`.`alumno_id`)) join `materias` `m` on(`m`.`id` = `i`.`materia_id`)) join `clases` `c` on(`c`.`materia_id` = `m`.`id` and `c`.`estado` = 'finalizada')) left join `asistencias` `a` on(`a`.`alumno_id` = `i`.`alumno_id` and `a`.`clase_id` = `c`.`id`)) group by `i`.`alumno_id`,`m`.`id` */;
