/*!50001 CREATE ALGORITHM=UNDEFINED */
/*!50013 DEFINER=`root`@`localhost` SQL SECURITY DEFINER */
/*!50001 VIEW `v_resumen_clases` AS select `c`.`id` AS `clase_id`,`m`.`nombre` AS `materia`,`m`.`codigo` AS `codigo`,`m`.`curso` AS `curso`,concat(`u`.`nombre`,' ',`u`.`apellido`) AS `profesor`,`c`.`fecha` AS `fecha`,`c`.`hora_inicio` AS `hora_inicio`,`c`.`duracion_min` AS `duracion_min`,`c`.`aula` AS `aula`,`c`.`modalidad` AS `modalidad`,`c`.`estado` AS `estado`,count(distinct `i`.`alumno_id`) AS `total_alumnos`,sum(`a`.`estado` in ('presente','tardanza')) AS `presentes`,count(distinct `i`.`alumno_id`) - coalesce(sum(`a`.`estado` in ('presente','tardanza')),0) AS `ausentes`,round(sum(`a`.`estado` in ('presente','tardanza')) / nullif(count(distinct `i`.`alumno_id`),0) * 100,1) AS `porcentaje` from ((((`clases` `c` join `materias` `m` on(`m`.`id` = `c`.`materia_id`)) left join `usuarios` `u` on(`u`.`id` = `m`.`profesor_id`)) left join `inscripciones` `i` on(`i`.`materia_id` = `m`.`id`)) left join `asistencias` `a` on(`a`.`clase_id` = `c`.`id` and `a`.`alumno_id` = `i`.`alumno_id`)) group by `c`.`id` */;
